package com.google.gson.internal.bind;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.TypeAdapterFactory;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.Test;

class TypeAdaptersTest {

  @Test
  void newFactory_create_returnsAdapterForUnboxed() {
    TypeAdapter<Number> adapter = mock(TypeAdapter.class);
    TypeAdapterFactory factory = TypeAdapters.newFactory(int.class, Integer.class, adapter);

    TypeToken<Integer> typeToken = TypeToken.get(int.class);
    @SuppressWarnings("unchecked")
    TypeAdapter<Integer> created = (TypeAdapter<Integer>) factory.create(mock(Gson.class), typeToken);

    assertSame(adapter, created);
  }

  @Test
  void newFactory_create_returnsAdapterForBoxed() {
    TypeAdapter<Number> adapter = mock(TypeAdapter.class);
    TypeAdapterFactory factory = TypeAdapters.newFactory(int.class, Integer.class, adapter);

    TypeToken<Integer> typeToken = TypeToken.get(Integer.class);
    @SuppressWarnings("unchecked")
    TypeAdapter<Integer> created = (TypeAdapter<Integer>) factory.create(mock(Gson.class), typeToken);

    assertSame(adapter, created);
  }

  @Test
  void newFactory_create_returnsNullForOtherType() {
    TypeAdapter<Number> adapter = mock(TypeAdapter.class);
    TypeAdapterFactory factory = TypeAdapters.newFactory(int.class, Integer.class, adapter);

    TypeToken<String> typeToken = TypeToken.get(String.class);
    TypeAdapter<String> created = factory.create(mock(Gson.class), typeToken);

    assertNull(created);
  }

  @Test
  void newFactory_toString_containsClassNamesAndAdapter() {
    TypeAdapter<Number> adapter = mock(TypeAdapter.class);
    TypeAdapterFactory factory = TypeAdapters.newFactory(int.class, Integer.class, adapter);

    String toString = factory.toString();
    assertTrue(toString.contains("int"));
    assertTrue(toString.contains("java.lang.Integer"));
    assertTrue(toString.contains(adapter.toString()));
  }
}
